-- Acts 26 — Paul Before Agrippa: Repentance, Light, and the Risen Christ
-- Theme: The Great Commission to Turn Men from Darkness to Light

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 26,
  'Acts 26 is the fullest and most majestic of Paul''s five defences — a gospel sermon preached to King Herod Agrippa II in the governor''s audience hall at Caesarea. Paul begins by owning his Pharisaic upbringing and the resurrection hope promised to the twelve tribes — "unto which promise our twelve tribes, instantly serving God day and night, hope to come." He rehearses his zealous persecution of the Way, then narrates the Damascus road for the third time in Acts, adding a detail found nowhere else: "it is hard for thee to kick against the pricks." The commission from Christ is given in its most expansive form — "to open their eyes, to turn them from darkness to light, and from the power of Satan unto God, that they may receive forgiveness of sins, and inheritance among them which are sanctified." Paul testifies that he "was not disobedient unto the heavenly vision," preaching repentance throughout the empire — saying nothing but what Moses and the prophets foretold, that Christ should suffer and be first to rise from the dead, showing light to the people and to the Gentiles. Festus interrupts: "Paul, thou art beside thyself; much learning doth make thee mad." Paul answers with perfect composure: "I am not mad, most noble Festus; but speak forth the words of truth and soberness." He turns to Agrippa: "King Agrippa, believest thou the prophets? I know that thou believest." Agrippa replies in the most famous half-conversion of Scripture: "Almost thou persuadest me to be a Christian." Paul''s longing answer — "I would to God, that not only thou, but also all that hear me this day, were both almost, and altogether such as I am, except these bonds" — closes the speech. In private conference the king and governor agree: "This man might have been set at liberty, if he had not appealed unto Caesar."',
  'The Great Commission to Turn Men from Darkness to Light',
  'ἐπιστρέψαι',
  'to turn, convert (epistrepsai) — Christ''s commission to Paul in v.18 to turn men from darkness to light and from Satan''s power to God.',
  '[{"range":"vv.1-3","title":"Paul Addresses the Expert King"},{"range":"vv.4-8","title":"The Pharisaic Hope of the Twelve Tribes"},{"range":"vv.9-11","title":"Paul the Persecutor of the Way"},{"range":"vv.12-18","title":"The Damascus Commission: Light, Liberty, Forgiveness"},{"range":"vv.19-23","title":"Obedient to the Heavenly Vision"},{"range":"vv.24-29","title":"Festus Cries ''Mad''; Paul Pleads with Agrippa"},{"range":"vv.30-32","title":"''Might Have Been Set at Liberty''"}]'::jsonb
FROM books b WHERE b.name = 'Acts'
ON CONFLICT (book_id, chapter_number) DO UPDATE SET
  overview = EXCLUDED.overview,
  theme = EXCLUDED.theme,
  key_word_original = EXCLUDED.key_word_original,
  key_word_meaning = EXCLUDED.key_word_meaning,
  outline = EXCLUDED.outline;

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'Then Agrippa said unto Paul, Thou art permitted to speak for thyself. Then Paul stretched forth the hand, and answered for himself:',
      'Ἀγρίππας δὲ πρὸς τὸν Παῦλον ἔφη, Ἐπιτρέπεταί σοι ὑπὲρ σεαυτοῦ λέγειν. Τότε ὁ Παῦλος ἀπελογεῖτο, ἐκτείνας τὴν χεῖρα,',
      'Agrippas de pros ton Paulon ephē, Epitrepetai soi hyper seautou legein. Tote ho Paulos apelogeito, ekteinas tēn cheira,',
      'Agrippa, not Festus, presides — appropriate since the king is the Jewish expert being consulted. Ekteinas tēn cheira — the classical rhetorical gesture for opening a formal speech.',
      'The apostle stands bound, his hand stretched in the posture of an orator. Chains cannot diminish the dignity of a gospel ambassador.'),
  (2, 'I think myself happy, king Agrippa, because I shall answer for myself this day before thee touching all the things whereof I am accused of the Jews:',
      'Περὶ πάντων ὧν ἐγκαλοῦμαι ὑπὸ Ἰουδαίων, βασιλεῦ Ἀγρίππα, ἥγημαι ἐμαυτὸν μακάριον, μέλλων ἀπολογεῖσθαι ἐπὶ σοῦ σήμερον·',
      'Peri pantōn hōn enkaloumai hypo Ioudaiōn, basileu Agrippa, hēgēmai emauton makarion, mellōn apologeisthai epi sou sēmeron;',
      'Makarion — "blessed, happy." No flattery; Paul genuinely rejoices for an informed audience. The matters are Jewish; Agrippa is Jewish-expert.',
      'The Christian counts it joy to answer for his faith before any who will truly hear. The apostle''s beatitudes extend to the dock.'),
  (3, 'Especially because I know thee to be expert in all customs and questions which are among the Jews: wherefore I beseech thee to hear me patiently.',
      'μάλιστα γνώστην ὄντα σε εἰδὼς πάντων τῶν κατὰ Ἰουδαίους ἐθῶν τε καὶ ζητημάτων· διὸ δέομαί σου, μακροθύμως ἀκοῦσαί μου.',
      'malista gnōstēn onta se eidōs pantōn tōn kata Ioudaious ethōn te kai zētēmatōn; dio deomai sou, makrothymōs akousai mou.',
      'Agrippa II had been entrusted by Claudius with oversight of the temple and appointment of the high priest (Josephus, Ant. 20.1.3; 20.9.4). He was genuinely learned in Jewish law and tradition.',
      'Paul begins by making his hearer a partner in the testimony. The gospel speaker appeals to what his audience already knows.'),
  (4, 'My manner of life from my youth, which was at the first among mine own nation at Jerusalem, know all the Jews;',
      'Τὴν μὲν οὖν βίωσίν μου τὴν ἐκ νεότητος, τὴν ἀπ᾽ ἀρχῆς γενομένην ἐν τῷ ἔθνει μου ἐν Ἱεροσολύμοις, ἴσασι πάντες οἱ Ἰουδαῖοι,',
      'Tēn men oun biōsin mou tēn ek neotētos, tēn ap archēs genomenēn en tō ethnei mou en Hierosolymois, isasi pantes hoi Ioudaioi,',
      'Biōsis — NT hapax, "manner of life." Paul''s boyhood years were spent in Jerusalem — confirmed by 22:3.',
      'The Christian''s testimony rests on verifiable biography. Paul''s past is known to those who now accuse him.'),
  (5, 'Which knew me from the beginning, if they would testify, that after the most straitest sect of our religion I lived a Pharisee.',
      'προγινώσκοντές με ἄνωθεν, ἐὰν θέλωσι μαρτυρεῖν, ὅτι κατὰ τὴν ἀκριβεστάτην αἵρεσιν τῆς ἡμετέρας θρησκείας ἔζησα Φαρισαῖος.',
      'proginōskontes me anōthen, ean thelōsi martyrein, hoti kata tēn akribestatēn hairesin tēs hēmeteras thrēskeias ezēsa Pharisaios.',
      'Akribestatēn ("most strict/exact") — Pharisaism was the most meticulous of the Jewish parties. Cf. Phil 3:5-6 for parallel credentials.',
      'Christianity is not the abandonment of zeal for God but its redirection to the Christ whom zeal was always meant to find.'),
  (6, 'And now I stand and am judged for the hope of the promise made of God unto our fathers:',
      'καὶ νῦν ἐπ᾽ ἐλπίδι τῆς πρὸς τοὺς πατέρας ἐπαγγελίας γενομένης ὑπὸ τοῦ Θεοῦ, ἕστηκα κρινόμενος,',
      'kai nyn ep elpidi tēs pros tous pateras epangelias genomenēs hypo tou Theou, hestēka krinomenos,',
      'The "promise made unto our fathers" is messianic and eschatological (Gen 3:15; 12:3; 22:18; 2 Sam 7:12-13; Isa 9:6-7). Paul''s "crime" is believing God''s own promises.',
      'Christianity is the fulfilment, not the rejection, of the covenant with Abraham. The apostle stands trial for Jewish hope come to pass.'),
  (7, 'Unto which promise our twelve tribes, instantly serving God day and night, hope to come. For which hope''s sake, king Agrippa, I am accused of the Jews.',
      'εἰς ἣν τὸ δωδεκάφυλον ἡμῶν ἐν ἐκτενείᾳ νύκτα καὶ ἡμέραν λατρεῦον ἐλπίζει καταντῆσαι· περὶ ἧς ἐλπίδος ἐγκαλοῦμαι, βασιλεῦ Ἀγρίππα, ὑπὸ τῶν Ἰουδαίων.',
      'eis hēn to dōdekaphylon hēmōn en ekteneia nykta kai hēmeran latreuon elpizei katantēsai; peri hēs elpidos enkaloumai, basileu Agrippa, hypo tōn Ioudaiōn.',
      'The "twelve tribes" (dōdekaphylon) — Paul speaks of Israel as a whole, not merely Judaea. "Instantly" (en ekteneia) = earnestly, intently.',
      'The hope of Israel and the faith of the apostles are one unbroken line. Christians worship the God of Abraham who keeps promise to His chosen.'),
  (8, 'Why should it be thought a thing incredible with you, that God should raise the dead?',
      'τί ἄπιστον κρίνεται παρ᾽ ὑμῖν, εἰ ὁ Θεὸς νεκροὺς ἐγείρει;',
      'ti apiston krinetai par hymin, ei ho Theos nekrous egeirei?',
      'Paul challenges the audience''s scepticism directly. If God exists, resurrection is rational; if He does not, nothing else matters.',
      'The resurrection is not an afterthought of Christian faith but a necessary corollary of belief in the living God. If the Creator cannot raise the dead, He is not the Creator.'),
  (9, 'I verily thought with myself, that I ought to do many things contrary to the name of Jesus of Nazareth.',
      'Ἐγὼ μὲν οὖν ἔδοξα ἐμαυτῷ πρὸς τὸ ὄνομα Ἰησοῦ τοῦ Ναζωραίου δεῖν πολλὰ ἐναντία πρᾶξαι·',
      'Egō men oun edoxa emautō pros to onoma Iēsou tou Nazōraiou dein polla enantia praxai;',
      'Paul''s zeal was conscientious. He truly thought he was defending God. Sincere zeal without knowledge is still destructive (Rom 10:2).',
      'Conscience apart from truth becomes a rod for the saints. Paul''s candour confesses that good intentions never saved a single heart.'),
  (10, 'Which thing I also did in Jerusalem: and many of the saints did I shut up in prison, having received authority from the chief priests; and when they were put to death, I gave my voice against them.',
      'ὃ καὶ ἐποίησα ἐν Ἱεροσολύμοις, καὶ πολλοὺς τῶν ἁγίων ἐγὼ φυλακαῖς κατέκλεισα, τὴν παρὰ τῶν ἀρχιερέων ἐξουσίαν λαβών, ἀναιρουμένων τε αὐτῶν κατήνεγκα ψῆφον.',
      'ho kai epoiēsa en Hierosolymois, kai pollous tōn hagiōn egō phylakais katekleisa, tēn para tōn archiereōn exousian labōn, anairoumenōn te autōn katēnenka psēphon.',
      'Psēphon — "pebble," voting-stone dropped in urns. Paul had been a member of the Sanhedrin''s executive or a similar council, voting for capital sentences against Christians.',
      'The apostle does not hide his worst chapter. Grace is magnified by the murderer who now preaches mercy.'),
  (11, 'And I punished them oft in every synagogue, and compelled them to blaspheme; and being exceedingly mad against them, I persecuted them even unto strange cities.',
      'καὶ κατὰ πάσας τὰς συναγωγὰς πολλάκις τιμωρῶν αὐτούς, ἠνάγκαζον βλασφημεῖν· περισσῶς τε ἐμμαινόμενος αὐτοῖς, ἐδίωκον ἕως καὶ εἰς τὰς ἔξω πόλεις.',
      'kai kata pasas tas synagōgas pollakis timōrōn autous, ēnankazon blasphēmein; perissōs te emmainomenos autois, ediōkon heōs kai eis tas exō poleis.',
      'Emmainomenos ("exceedingly mad") — Paul''s rage is confessed as literal madness. Synagogues functioned as local courts that could administer corporal punishment (cf. 2 Cor 11:24).',
      'The converted persecutor names his former fury "madness." Only the Spirit can expose the rational-seeming violence of the unregenerate religious heart.'),
  (12, 'Whereupon as I went to Damascus with authority and commission from the chief priests,',
      'Ἐν οἷς καὶ πορευόμενος εἰς τὴν Δαμασκόν, μετ᾽ ἐξουσίας καὶ ἐπιτροπῆς τῆς παρὰ τῶν ἀρχιερέων,',
      'En hois kai poreuomenos eis tēn Damaskon, met exousias kai epitropēs tēs para tōn archiereōn,',
      'Paul is now the bound prisoner of the Christ whose followers he once bound.',
      'The chains have changed hands. The servant of God who once carried warrants now carries a gospel for the same nations.'),
  (13, 'At midday, O king, I saw in the way a light from heaven, above the brightness of the sun, shining round about me and them which journeyed with me.',
      'ἡμέρας μέσης, κατὰ τὴν ὁδὸν εἶδον, βασιλεῦ, οὐρανόθεν ὑπὲρ τὴν λαμπρότητα τοῦ ἡλίου, περιλάμψαν με φῶς καὶ τοὺς σὺν ἐμοὶ πορευομένους.',
      'hēmeras mesēs, kata tēn hodon eidon, basileu, ouranothen hyper tēn lamprotēta tou hēliou, perilampsan me phōs kai tous syn emoi poreuomenous.',
      '"Above the brightness of the sun" — this detail, unique to the third retelling, drives home the supernatural origin.',
      'The glory of the risen Christ outshines the noonday sun. No merely natural phenomenon can account for the conversion of Saul.'),
  (14, 'And when we were all fallen to the earth, I heard a voice speaking unto me, and saying in the Hebrew tongue, Saul, Saul, why persecutest thou me? it is hard for thee to kick against the pricks.',
      'πάντων δὲ καταπεσόντων ἡμῶν εἰς τὴν γῆν, ἤκουσα φωνὴν λαλοῦσαν πρός με, καὶ λέγουσαν τῇ Ἑβραΐδι διαλέκτῳ, Σαούλ, Σαούλ, τί με διώκεις; σκληρόν σοι πρὸς κέντρα λακτίζειν.',
      'pantōn de katapesontōn hēmōn eis tēn gēn, ēkousa phōnēn lalousan pros me, kai legousan tē Hebraïdi dialektō, Saoul, Saoul, ti me diōkeis? sklēron soi pros kentra laktizein.',
      '"Kick against the pricks" — a Greek proverb (Euripides, Pindar) of the ox spurning the driver''s goad (kentron). Found only in this retelling. Suggests Paul had been resisting deep convictions for some time — perhaps at Stephen''s death.',
      'Unregenerate hearts wound themselves on God''s unseen goad. Conscience, unheeded, bleeds the soul.'),
  (15, 'And I said, Who art thou, Lord? And he said, I am Jesus whom thou persecutest.',
      'Ἐγὼ δὲ εἶπον, Τίς εἶ, Κύριε; Ὁ δὲ εἶπεν, Ἐγώ εἰμι Ἰησοῦς ὃν σὺ διώκεις.',
      'Egō de eipon, Tis ei, Kyrie? Ho de eipen, Egō eimi Iēsous hon sy diōkeis.',
      'Identification: Jesus is Lord; persecution of His people is persecution of Him.',
      'The risen Christ is personally identified with His church. Her wounds are His wounds, and her glory is His.'),
  (16, 'But rise, and stand upon thy feet: for I have appeared unto thee for this purpose, to make thee a minister and a witness both of these things which thou hast seen, and of those things in the which I will appear unto thee;',
      'ἀλλὰ ἀνάστηθι, καὶ στῆθι ἐπὶ τοὺς πόδας σου· εἰς τοῦτο γὰρ ὤφθην σοι, προχειρίσασθαί σε ὑπηρέτην καὶ μάρτυρα ὧν τε εἶδες, ὧν τε ὀφθήσομαί σοι,',
      'alla anastēthi, kai stēthi epi tous podas sou; eis touto gar ōphthēn soi, procheirisasthai se hypēretēn kai martyra hōn te eides, hōn te ophthēsomai soi,',
      'Hypēretēn — "under-oarsman," servant of the highest rank (Luke 1:2). Martyra — "witness." Future appearances are promised (cf. 18:9; 22:17-18; 23:11; 27:23-24; 2 Cor 12:1-4).',
      'Christ''s call commissions for present and future. The servant-witness is sent with a word yet to be completed in his own unfolding story.'),
  (17, 'Delivering thee from the people, and from the Gentiles, unto whom now I send thee,',
      'ἐξαιρούμενός σε ἐκ τοῦ λαοῦ καὶ τῶν ἐθνῶν, εἰς οὓς νῦν σε ἀποστέλλω,',
      'exairoumenos se ek tou laou kai tōn ethnōn, eis hous nyn se apostellō,',
      '"People" (laos) = Israel; "Gentiles" (ethnē) = the nations. The Lord will rescue Paul from both opposing peoples even as He sends him to reach both.',
      'Mission and protection are paired in the Lord''s commission. He who sends also preserves until the work is done.'),
  (18, 'To open their eyes, and to turn them from darkness to light, and from the power of Satan unto God, that they may receive forgiveness of sins, and inheritance among them which are sanctified by faith that is in me.',
      'ἀνοῖξαι ὀφθαλμοὺς αὐτῶν, καὶ ἐπιστρέψαι ἀπὸ σκότους εἰς φῶς καὶ τῆς ἐξουσίας τοῦ Σατανᾶ ἐπὶ τὸν Θεόν, τοῦ λαβεῖν αὐτοὺς ἄφεσιν ἁμαρτιῶν, καὶ κλῆρον ἐν τοῖς ἡγιασμένοις πίστει τῇ εἰς ἐμέ.',
      'anoixai ophthalmous autōn, kai epistrepsai apo skotous eis phōs kai tēs exousias tou Satana epi ton Theon, tou labein autous aphesin hamartiōn, kai klēron en tois hēgiasmenois pistei tē eis eme.',
      'The most complete statement of the gospel commission in Acts. Four transfers: eyes opened / darkness to light / Satan''s power to God / unforgiven to inheritance. "By faith that is in me" — faith''s object is Christ.',
      'The gospel is a work of new creation. Light replaces darkness, God replaces Satan, forgiveness replaces guilt, inheritance replaces exclusion — all by faith in Christ alone.'),
  (19, 'Whereupon, O king Agrippa, I was not disobedient unto the heavenly vision:',
      'Ὅθεν, βασιλεῦ Ἀγρίππα, οὐκ ἐγενόμην ἀπειθὴς τῇ οὐρανίῳ ὀπτασίᾳ,',
      'Hothen, basileu Agrippa, ouk egenomēn apeithēs tē ouraniō optasia,',
      'Litotes: "not disobedient" = fervently obedient. The apostle underlines his compliance with heavenly orders.',
      'A heavenly vision requires earthly obedience. The servant who sees Christ must walk the way Christ directs.'),
  (20, 'But shewed first unto them of Damascus, and at Jerusalem, and throughout all the coasts of Judaea, and then to the Gentiles, that they should repent and turn to God, and do works meet for repentance.',
      'ἀλλὰ τοῖς ἐν Δαμασκῷ πρῶτον καὶ Ἱεροσολύμοις, εἰς πᾶσάν τε τὴν χώραν τῆς Ἰουδαίας, καὶ τοῖς ἔθνεσιν, ἀπαγγέλλων μετανοεῖν, καὶ ἐπιστρέφειν ἐπὶ τὸν Θεόν, ἄξια τῆς μετανοίας ἔργα πράσσοντας.',
      'alla tois en Damaskō prōton kai Hierosolymois, eis pasan te tēn chōran tēs Ioudaias, kai tois ethnesin, apangellōn metanoein, kai epistrephein epi ton Theon, axia tēs metanoias erga prassontas.',
      'The three-fold content of Paul''s preaching: repent, turn to God, bring forth works worthy of repentance. "Axia tēs metanoias erga" echoes John the Baptist (Luke 3:8).',
      'Repentance and faith are inseparable from fruitful living. Genuine conversion is demonstrated in a transformed walk, not mere profession.'),
  (21, 'For these causes the Jews caught me in the temple, and went about to kill me.',
      'Ἕνεκα τούτων με οἱ Ἰουδαῖοι συλλαβόμενοι ἐν τῷ ἱερῷ ἐπειρῶντο διαχειρίσασθαι.',
      'Heneka toutōn me hoi Ioudaioi syllabomenoi en tō hierō epeirōnto diacheirisasthai.',
      'Diacheirisasthai — literally "lay hands in violence upon." This is the real ground of Jewish hostility — the Gentile-inclusive mission.',
      'The gospel''s deepest offence is its welcome of the outsider. Where exclusivity rules, the universal gospel always stirs up resistance.'),
  (22, 'Having therefore obtained help of God, I continue unto this day, witnessing both to small and great, saying none other things than those which the prophets and Moses did say should come:',
      'Ἐπικουρίας οὖν τυχὼν τῆς παρὰ τοῦ Θεοῦ, ἄχρι τῆς ἡμέρας ταύτης ἕστηκα μαρτυρούμενος μικρῷ τε καὶ μεγάλῳ, οὐδὲν ἐκτὸς λέγων ὧν τε οἱ προφῆται ἐλάλησαν μελλόντων γίνεσθαι καὶ Μωϋσῆς,',
      'Epikourias oun tychōn tēs para tou Theou, achri tēs hēmeras tautēs hestēka martyroumenos mikrō te kai megalō, ouden ektos legōn hōn te hoi prophētai elalēsan mellontōn ginesthai kai Mōysēs,',
      'Epikouria — "help, assistance." Paul claims continuity with Moses and the prophets — he preaches what they foretold.',
      'Christian preaching adds nothing to Scripture. The gospel is what Moses and the prophets said should come; the apostle only unfolds what God already told.'),
  (23, 'That Christ should suffer, and that he should be the first that should rise from the dead, and should shew light unto the people, and to the Gentiles.',
      'εἰ παθητὸς ὁ Χριστός, εἰ πρῶτος ἐξ ἀναστάσεως νεκρῶν φῶς μέλλει καταγγέλλειν τῷ λαῷ καὶ τοῖς ἔθνεσι.',
      'ei pathētos ho Christos, ei prōtos ex anastaseōs nekrōn phōs mellei katangellein tō laō kai tois ethnesi.',
      'Three OT predictions compressed: a suffering Messiah (Isa 53), the firstborn from the dead (Ps 16:10), light to Jews and Gentiles (Isa 49:6; 60:1-3). The whole gospel in one verse.',
      'The gospel is not optional innovation. The suffering, resurrection, and universal light of Christ are written into the Old Testament and preached by the apostle.'),
  (24, 'And as he thus spake for himself, Festus said with a loud voice, Paul, thou art beside thyself; much learning doth make thee mad.',
      'Ταῦτα δὲ αὐτοῦ ἀπολογουμένου, ὁ Φῆστος μεγάλῃ τῇ φωνῇ ἔφη, Μαίνῃ, Παῦλε· τὰ πολλά σε γράμματα εἰς μανίαν περιτρέπει.',
      'Tauta de autou apologoumenou, ho Phēstos megalē tē phōnē ephē, Mainē, Paule; ta polla se grammata eis manian peritrepei.',
      'Mainē — "thou art mad, raving." Festus the pagan cannot follow the Old-Testament logic of a suffering Messiah risen from the dead. "Much learning" (polla grammata) acknowledges Paul''s erudition.',
      'The cross remains foolishness to natural men (1 Cor 1:23). The gospel''s deep intelligibility requires spiritual ears.'),
  (25, 'But he said, I am not mad, most noble Festus; but speak forth the words of truth and soberness.',
      'Ὁ δέ, Οὐ μαίνομαι, φησί, κράτιστε Φῆστε, ἀλλὰ ἀληθείας καὶ σωφροσύνης ῥήματα ἀποφθέγγομαι.',
      'Ho de, Ou mainomai, phēsi, kratiste Phēste, alla alētheias kai sōphrosynēs rhēmata apophthengomai.',
      'Apophthengomai ("utter, declare") is a lofty word for inspired or deliberate speech (cf. 2:4, 14). Sōphrosynē = soundness of mind.',
      'Christian testimony is the soberest of speech. What the world calls madness is the truest sanity, spoken in clear measure.'),
  (26, 'For the king knoweth of these things, before whom also I speak freely: for I am persuaded that none of these things are hidden from him; for this thing was not done in a corner.',
      'Ἐπίσταται γὰρ περὶ τούτων ὁ βασιλεύς, πρὸς ὃν καὶ παρρησιαζόμενος λαλῶ· λανθάνειν γὰρ αὐτὸν τι τούτων οὐ πείθομαι οὐδέν· οὐ γάρ ἐστιν ἐν γωνίᾳ πεπραγμένον τοῦτο.',
      'Epistatai gar peri toutōn ho basileus, pros hon kai parrēsiazomenos lalō; lanthanein gar auton ti toutōn ou peithomai ouden; ou gar estin en gōnia pepragmenon touto.',
      '"Not done in a corner" — a famous idiom for public, well-attested events. The crucifixion, resurrection, and Christian movement were not hidden cults but public history.',
      'Christianity is a public event, not a secret mystery-religion. The life, death, and resurrection of Christ are facts done in the open light of Jerusalem.'),
  (27, 'King Agrippa, believest thou the prophets? I know that thou believest.',
      'πιστεύεις, βασιλεῦ Ἀγρίππα, τοῖς προφήταις; οἶδα ὅτι πιστεύεις.',
      'pisteueis, basileu Agrippa, tois prophētais? oida hoti pisteueis.',
      'Paul turns evangelist, pressing Agrippa with direct appeal. Since the king confessed the prophets and Paul has shown the prophets foretold Christ, the logical step is faith.',
      'The gospel preacher lovingly closes every argument with application. Conviction without appeal is preaching that stops short of its errand.'),
  (28, 'Then Agrippa said unto Paul, Almost thou persuadest me to be a Christian.',
      'Ὁ δὲ Ἀγρίππας πρὸς τὸν Παῦλον ἔφη, Ἐν ὀλίγῳ με πείθεις Χριστιανὸν γενέσθαι.',
      'Ho de Agrippas pros ton Paulon ephē, En oligō me peitheis Christianon genesthai.',
      '"Almost" — en oligō, "in a little (while/degree)." Possibly ironic ("briefly"), possibly genuine conviction held in check. "Christian" (Christianos) is used of believers for only the third time in the NT (Acts 11:26; 1 Pet 4:16).',
      'Half-converted is still unconverted. The "almost" of Agrippa is the saddest word in Acts — persuasion without surrender.'),
  (29, 'And Paul said, I would to God, that not only thou, but also all that hear me this day, were both almost, and altogether such as I am, except these bonds.',
      'Ὁ δὲ Παῦλος εἶπεν, Εὐξαίμην ἂν τῷ Θεῷ, καὶ ἐν ὀλίγῳ καὶ ἐν πολλῷ οὐ μόνον σέ, ἀλλὰ καὶ πάντας τοὺς ἀκούοντάς μου σήμερον γενέσθαι τοιούτους ὁποῖος κἀγώ εἰμι, παρεκτὸς τῶν δεσμῶν τούτων.',
      'Ho de Paulos eipen, Euxaimēn an tō Theō, kai en oligō kai en pollō ou monon se, alla kai pantas tous akouontas mou sēmeron genesthai toioutous hopoios kagō eimi, parektos tōn desmōn toutōn.',
      'Paul''s loving retort: "both in little and in much" — take away only the chains. The evangelist would have his adversaries possess all he has except his bonds.',
      'The pastor''s heart wants only conversion, not comfort. Paul would exchange places with every hearer except for his chains — those he would carry twice over for their sake.'),
  (30, 'And when he had thus spoken, the king rose up, and the governor, and Bernice, and they that sat with them:',
      'Καὶ ταῦτα εἰπόντος αὐτοῦ, ἀνέστη ὁ βασιλεύς, καὶ ὁ ἡγεμών, ἥ τε Βερνίκη, καὶ οἱ συγκαθήμενοι αὐτοῖς·',
      'Kai tauta eipontos autou, anestē ho basileus, kai ho hēgemōn, hē te Bernikē, kai hoi synkathēmenoi autois;',
      'The audience ends abruptly — Agrippa rises before any further appeal can come.',
      'Hearers sometimes stand up to end a sermon rather than face its conclusion. The feet often rescue the heart from conviction.'),
  (31, 'And when they were gone aside, they talked between themselves, saying, This man doeth nothing worthy of death or of bonds.',
      'καὶ ἀναχωρήσαντες ἐλάλουν πρὸς ἀλλήλους, λέγοντες, ὅτι Οὐδὲν θανάτου ἄξιον ἢ δεσμῶν πράσσει ὁ ἄνθρωπος οὗτος.',
      'kai anachōrēsantes elaloun pros allēlous, legontes, hoti Ouden thanatou axion ē desmōn prassei ho anthrōpos houtos.',
      'The sixth declaration of Paul''s innocence — and now by a Jewish king. The verdict confirms the apostle''s legal innocence beyond reasonable doubt.',
      'The gospel''s preachers are cleared by every honest tribunal. Only religious hatred, not justice, keeps Paul''s chains.'),
  (32, 'Then said Agrippa unto Festus, This man might have been set at liberty, if he had not appealed unto Caesar.',
      'Ἀγρίππας δὲ τῷ Φήστῳ ἔφη, Ἀπολελύσθαι ἐδύνατο ὁ ἄνθρωπος οὗτος, εἰ μὴ ἐπεκέκλητο Καίσαρα.',
      'Agrippas de tō Phēstō ephē, Apolelysthai edynato ho anthrōpos houtos, ei mē epekeklēto Kaisara.',
      'Agrippa''s regret. The appeal cannot be withdrawn; the case has been transferred to Rome. Paul''s providentially appointed road to the capital is now irreversible.',
      'What looked like a tactical choice was a divine appointment. Paul''s appeal is not a wasted move but the Lord''s chosen vehicle to Rome.')
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Acts' AND c.chapter_number = 26
ON CONFLICT (chapter_id, verse_number) DO UPDATE SET
  kjv_text = EXCLUDED.kjv_text,
  original_text = EXCLUDED.original_text,
  transliteration = EXCLUDED.transliteration,
  study_note = EXCLUDED.study_note,
  doctrinal_note = EXCLUDED.doctrinal_note;

INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'ἐκτείνας τὴν χεῖρα', 'ekteinas tēn cheira', 'G1614/G5495', 'Stretching out the hand — classical orator''s gesture.', 1),
  (2, 'μακάριον', 'makarion', 'G3107', 'Blessed, happy — Paul''s joy at informed audience.', 2),
  (3, 'γνώστην', 'gnōstēn', 'G1109', 'Expert, knower — Agrippa''s Jewish competence.', 3),
  (4, 'βίωσιν', 'biōsin', 'G981', 'Manner of life — NT hapax.', 4),
  (5, 'ἀκριβεστάτην αἵρεσιν', 'akribestatēn hairesin', 'G196/G139', 'Most exact/strict sect — Pharisaism.', 5),
  (6, 'ἐπαγγελίας', 'epangelias', 'G1860', 'Promise — the Abrahamic/Davidic hope.', 6),
  (7, 'δωδεκάφυλον', 'dōdekaphylon', 'G1429', 'Twelve-tribe nation — all Israel.', 7),
  (7, 'ἐκτενείᾳ', 'ekteneia', 'G1616', 'Earnestness, intensity — day-and-night devotion.', 8),
  (9, 'ἐναντία', 'enantia', 'G1727', 'Contrary things — Paul''s prior hostility.', 9),
  (10, 'ψῆφον', 'psēphon', 'G5586', 'Voting-pebble — capital-case vote.', 10),
  (11, 'ἐμμαινόμενος', 'emmainomenos', 'G1693', 'Being exceedingly mad — Paul''s confessed rage.', 11),
  (11, 'βλασφημεῖν', 'blasphēmein', 'G987', 'To blaspheme — deny/curse Christ under torture.', 12),
  (13, 'λαμπρότητα', 'lamprotēta', 'G2987', 'Brilliance — of the noonday sun surpassed.', 13),
  (14, 'κέντρα λακτίζειν', 'kentra laktizein', 'G2759/G2979', 'To kick against the goads — Greek proverb of futile resistance.', 14),
  (16, 'ὑπηρέτην', 'hypēretēn', 'G5257', 'Under-rower, servant — minister of the word.', 15),
  (16, 'μάρτυρα', 'martyra', 'G3144', 'Witness — of what seen and future.', 16),
  (16, 'προχειρίσασθαί', 'procheirisasthai', 'G4400', 'To appoint by hand — sovereign designation.', 17),
  (17, 'ἐξαιρούμενός', 'exairoumenos', 'G1807', 'Delivering — rescuing from opposition.', 18),
  (18, 'ἐπιστρέψαι', 'epistrepsai', 'G1994', 'To turn — the great gospel verb.', 19),
  (18, 'ἐξουσίας τοῦ Σατανᾶ', 'exousias tou Satana', 'G1849/G4567', 'Power/authority of Satan — the dominion of darkness.', 20),
  (18, 'ἄφεσιν ἁμαρτιῶν', 'aphesin hamartiōn', 'G859/G266', 'Forgiveness of sins — release from guilt.', 21),
  (18, 'κλῆρον', 'klēron', 'G2819', 'Inheritance, lot — portion among the sanctified.', 22),
  (18, 'ἡγιασμένοις', 'hēgiasmenois', 'G37', 'Those sanctified — set-apart saints.', 23),
  (19, 'ἀπειθὴς', 'apeithēs', 'G545', 'Disobedient — Paul''s litotes for fervent obedience.', 24),
  (20, 'μετανοεῖν', 'metanoein', 'G3340', 'To repent — fundamental change of mind toward God.', 25),
  (20, 'ἄξια τῆς μετανοίας ἔργα', 'axia tēs metanoias erga', 'G514/G3341/G2041', 'Works worthy of repentance — evidentiary fruit.', 26),
  (23, 'παθητὸς', 'pathētos', 'G3805', 'Subject to suffering — of the Messiah (Isa 53).', 27),
  (23, 'πρῶτος ἐξ ἀναστάσεως', 'prōtos ex anastaseōs', 'G4413/G386', 'First from resurrection — the firstborn from the dead.', 28),
  (24, 'Μαίνῃ', 'Mainē', 'G3105', 'Thou art mad, raving — Festus''s verdict.', 29),
  (25, 'ἀληθείας καὶ σωφροσύνης', 'alētheias kai sōphrosynēs', 'G225/G4997', 'Truth and soberness — Paul''s characterization.', 30),
  (25, 'ἀποφθέγγομαι', 'apophthengomai', 'G669', 'To declare solemnly — inspired speech.', 31),
  (26, 'παρρησιαζόμενος', 'parrēsiazomenos', 'G3955', 'Speaking boldly, freely — apostolic frankness.', 32),
  (26, 'ἐν γωνίᾳ', 'en gōnia', 'G1137', 'In a corner — idiom for hidden/secret.', 33),
  (28, 'Ἐν ὀλίγῳ', 'En oligō', 'G3641', 'In little (time/measure) — Agrippa''s "almost."', 34),
  (28, 'Χριστιανὸν', 'Christianon', 'G5546', 'Christian — third NT use of this identifier.', 35),
  (29, 'δεσμῶν', 'desmōn', 'G1199', 'Bonds, chains — Paul''s literal fetters.', 36),
  (32, 'ἀπολελύσθαι', 'apolelysthai', 'G630', 'To have been set free — the hypothetical release.', 37)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Acts' AND c.chapter_number = 26 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

